package main

import (
    "context"
    "log"
    "net"
    "sync"

    "google.golang.org/grpc"
    pb "path/to/your/proto/files"
)

type server struct {
    pb.UnimplementedTransactionServiceServer
    balances sync.Map
}

func (s *server) CreateTransaction(ctx context.Context, req *pb.CreateTransactionRequest) (*pb.CreateTransactionResponse, error) {
    if req.TransactionType == "credit" {
        currentBalance, _ := s.balances.LoadOrStore(req.AccountId, 0.0)
        newBalance := currentBalance.(float64) + req.Amount
        s.balances.Store(req.AccountId, newBalance)
    } else if req.TransactionType == "debit" {
        currentBalance, _ := s.balances.LoadOrStore(req.AccountId, 0.0)
        newBalance := currentBalance.(float64) - req.Amount
        s.balances.Store(req.AccountId, newBalance)
    }
    return &pb.CreateTransactionResponse{TransactionId: "some-unique-id", Status: "success"}, nil
}

func (s *server) GetBalance(ctx context.Context, req *pb.GetBalanceRequest) (*pb.GetBalanceResponse, error) {
    balance, _ := s.balances.Load(req.AccountId)
    return &pb.GetBalanceResponse{Balance: balance.(float64)}, nil
}

func main() {
    lis, err := net.Listen("tcp", ":50051")
    if err != nil {
        log.Fatalf("failed to listen: %v", err)
    }
    s := grpc.NewServer()
    pb.RegisterTransactionServiceServer(s, &server{})
    if err := s.Serve(lis); err != nil {
        log.Fatalf("failed to serve: %v", err)
    }
}